onClick:
{{
SelectWarehouse.selectedOptionValue
appsmith.store.companyId

if (!SelectWarehouse.selectedOptionValue) {
  showAlert("Select warehouse first", "warning");
} else if (
  appsmith.store.roleCode === "ADMIN" ||
  JSON.stringify(appsmith.store.permissions || []).includes("warehouse.manage") ||
  JSON.stringify(appsmith.store.permissions || []).includes("sales.manage")
) {
  storeValue("warehouseId", SelectWarehouse.selectedOptionValue)
    .then(() => storeValue("warehouseLabel", SelectWarehouse.selectedOptionLabel))
    .then(() => closeModal("Warehouse"))
    .then(() => showAlert("Warehouse changed", "success"))
    .then(() => checkWarehousePermission.run())
    .catch(() => showAlert("Warehouse change failed", "error"));
} else {
  showAlert("You do not have access to this warehouse", "error");
}
}}
